        test.addMonths(0);
        assertEquals("2011-10-30T02:30:00.000+01:00", test.toString());
    }

    //-----------------------------------------------------------------------
    public void testAddDays_int1() {
        MutableDateTime test = new MutableDateTime(2002, 6, 9, 5, 6, 7, 8);
        test.addDays(17);
        assertEquals("2002-06-26T05:06:07.008+01:00", test.toString());
